struct GhosttyConfig {
    var fontFamily: String = "Menlo"
    var fontSize: CGFloat = 12
    var theme: String?
    var workingDirectory: String?
    var scrollbackLimit: Int = 10000
    var unfocusedSplitOpacity: Double = 0.7
    var unfocusedSplitFill: NSColor?
    var splitDividerColor: NSColor?

    var backgroundColor: NSColor = NSColor(hex: "#272822")!
    var backgroundOpacity: Double = 1.0
    var foregroundColor: NSColor = NSColor(hex: "#fdfff1")!
    var cursorColor: NSColor = NSColor(hex: "#c0c1b5")!
    var selectionBackground: NSColor = NSColor(hex: "#57584f")!

    var palette: [Int: NSColor] = [:]

    static func load(
        preferredColorScheme: ColorSchemePreference? = nil,
        useCache: Bool = true
    ) -> GhosttyConfig {
        let resolvedColorScheme = preferredColorScheme ?? currentColorSchemePreference()
        if useCache, let cached = cachedLoad(for: resolvedColorScheme) {
            return cached
        }
        let loaded = loadFromDisk(resolvedColorScheme)
        if useCache { storeCachedLoad(loaded, for: resolvedColorScheme) }
        return loaded
    }
}

@objc func cmux_performKeyEquivalent(with event: NSEvent) -> Bool {
    let firstResponderGhosttyView = cmuxOwningGhosttyView(for: self.firstResponder)
    let firstResponderWebView = self.firstResponder.flatMap {
        Self.cmuxOwningWebView(for: $0, in: self, event: event)
    }

    if let ghosttyView = firstResponderGhosttyView {
        if ghosttyView.hasMarkedText(),
           !event.modifierFlags.intersection(.deviceIndependentFlagsMask).contains(.command) {
            return cmux_performKeyEquivalent(with: event)
        }

        let flags = event.modifierFlags.intersection(.deviceIndependentFlagsMask)
        if !flags.contains(.command) {
            return ghosttyView.performKeyEquivalent(with: event)
        }
    }

    if firstResponderGhosttyView != nil,
       shouldRouteCommandEquivalentDirectlyToMainMenu(event),
       let mainMenu = NSApp.mainMenu {
        let consumedByMenu = mainMenu.performKeyEquivalent(with: event)
        if consumedByMenu { return true }
    }

    let result = cmux_performKeyEquivalent(with: event)
    return result
}

func addWorkspace(
    title: String? = nil,
    workingDirectory overrideWorkingDirectory: String? = nil,
    initialTerminalCommand: String? = nil,
    select: Bool = true,
    eagerLoadTerminal: Bool = false,
    placementOverride: NewWorkspacePlacement? = nil
) -> Workspace {
    let sourceWorkspace = selectedWorkspace
    let capturedTabs = tabs
    return withExtendedLifetime((capturedTabs, sourceWorkspace)) {
        let dir = preferredWorkingDirectoryForNewTab(workspace: sourceWorkspace)
        let font = inheritedTerminalFontPointsForNewWorkspace(workspace: sourceWorkspace)
        let insertIndex = newTabInsertIndex(
            snapshot: snapshot, placementOverride: placementOverride
        )
        let newWorkspace = makeWorkspaceForCreation(
            title: title ?? "Terminal \(nextTabCount)",
            workingDirectory: workingDirectory,
            portOrdinal: ordinal,
            configTemplate: inheritedConfig
        )
        var updatedTabs = tabs
        updatedTabs.insert(newWorkspace, at: insertIndex)
        tabs = updatedTabs
        if select { selectedTabId = newWorkspace.id }
        return newWorkspace
    }
}

final class Workspace: Identifiable, ObservableObject {
    let id: UUID
    @Published var title: String
    @Published var customTitle: String?
    @Published var isPinned: Bool = false
    @Published var customColor: String?
    @Published var currentDirectory: String

    let bonsplitController: BonsplitController
    @Published private(set) var panels: [UUID: any Panel] = [:]

    var focusedPanelId: UUID? {
        guard let paneId = bonsplitController.focusedPaneId,
              let tab = bonsplitController.selectedTab(inPane: paneId) else {
            return nil
        }
        return panelIdFromSurfaceId(tab.id)
    }

    var focusedTerminalPanel: TerminalPanel? {
        guard let panelId = focusedPanelId,
              let panel = panels[panelId] as? TerminalPanel else {
            return nil
        }
        return panel
    }
}

func cmuxShouldApplyWindowGlass(
    sidebarBlendMode: String,
    bgGlassEnabled: Bool,
    glassEffectAvailable _: Bool
) -> Bool {
    sidebarBlendMode == "behindWindow" && bgGlassEnabled
}

static func stringContents(from pasteboard: NSPasteboard) -> String? {
    if let urls = pasteboard.readObjects(forClasses: [NSURL.self]) as? [URL],
       !urls.isEmpty {
        return urls
            .map { $0.isFileURL ? escapeForShell($0.path) : $0.absoluteString }
            .joined(separator: " ")
    }
    let htmlText = attributedStringContents(from: pasteboard, type: .html, documentType: .html)
    if hasImageData(in: pasteboard),
       let html = pasteboard.string(forType: .html),
       htmlHasNoVisibleText(html) {
        return nil
    }
    if let value = plainTextContents(from: pasteboard) {
        return value
    }
    return htmlText
}

enum WorkspaceAttentionFlashReason: String, Equatable, Sendable {
    case navigation
    case notificationArrival
    case notificationDismiss
    case manualUnreadDismiss
    case debug
}

enum WorkspaceAttentionCoordinator {
    static func decideFlash(
        targetPanelID: UUID,
        reason: WorkspaceAttentionFlashReason,
        persistentState: WorkspaceAttentionPersistentState
    ) -> WorkspaceAttentionFlashDecision {
        let isAllowed: Bool
        switch reason {
        case .navigation:
            isAllowed = !persistentState.hasCompetingIndicator(for: targetPanelID)
        case .notificationArrival, .notificationDismiss,
             .manualUnreadDismiss, .debug:
            isAllowed = true
        }
        return WorkspaceAttentionFlashDecision(
            panelID: targetPanelID,
            reason: reason,
            isAllowed: isAllowed
        )
    }
}
